class Solution:
    def maximizeWin(self, prizePositions, k):
        n = len(prizePositions)
        if n == 0:
            return 0
        best = [0] * (n + 1)
        ans = 0
        j = 0
        for i in range(n):
            while prizePositions[i] - prizePositions[j] > k:
                j += 1
            cur = i - j + 1
            ans = max(ans, cur + best[j])
            best[i + 1] = max(best[i], cur)
        return ans

