var maximizeWin = function(prizePositions, k) {
    const n = prizePositions.length;
    if (n === 0) return 0;
    const best = new Array(n + 1).fill(0);
    let ans = 0;
    let j = 0;
    for (let i = 0; i < n; i++) {
        while (prizePositions[i] - prizePositions[j] > k) j++;
        const cur = i - j + 1;
        ans = Math.max(ans, cur + best[j]);
        best[i + 1] = Math.max(best[i], cur);
    }
    return ans;
};
